/**
 * bundle-css.js
 *
 * Concatenates and minifies all project stylesheets into /css/bundle.min.css
 */
const fs = require('fs');
const path = require('path');

const cssFiles = [
  'assets/css/critical.css',
  'assets/css/styles.css',
  'assets/css/futuristic-global.css',
  'assets/css/color-dynamics.css',
  'assets/css/enhancements.css',
  'assets/css/resources.css',
  'assets/css/autogenerated-utility.css'
];

const rootDir = path.join(__dirname, '../');
const outputFile = path.join(rootDir, 'assets/css/bundle.min.css');

console.log('=== STARTING CSS BUNDLING ===');

let bundledContent = '';

cssFiles.forEach(file => {
  const filePath = path.join(rootDir, file);
  if (fs.existsSync(filePath)) {
    console.log(`Bundling CSS: ${file}`);
    const content = fs.readFileSync(filePath, 'utf8');
    bundledContent += `/* --- ${file} --- */\n${content}\n`;
  } else {
    console.warn(`Warning: CSS file not found: ${filePath}`);
  }
});

// Simple minifier (remove comments, extra whitespace, newlines)
function minifyCss(css) {
  return css
    .replace(/\/\*[\s\S]*?\*\//g, '') // remove comments
    .replace(/\s+/g, ' ')             // collapse whitespace
    .replace(/ ?\{ ?/g, '{')          // clean up spacing around braces
    .replace(/ ?\} ?/g, '}')
    .replace(/ ?; ?/g, ';')           // clean up spacing around semicolons
    .replace(/ ?: ?/g, ':')           // clean up spacing around colons
    .trim();
}

try {
  const minified = minifyCss(bundledContent);
  fs.writeFileSync(outputFile, minified, 'utf8');
  console.log(`\nSuccessfully bundled and minified CSS into: ${outputFile} (Size: ${minified.length} bytes)`);
  console.log('=== CSS BUNDLING COMPLETE ===');
} catch (err) {
  console.error('Error writing CSS bundle:', err);
  process.exit(1);
}
